{"code":"const prs = github.list_pull_requests({ state: "merged" });
prs.length;
prs.slice(0, 3).map(p => ({ number: p.number, title: p.title, body: (p.body || "").slice(0, 200) }));
"}

{"code":"const extractLinearId = (body) => {
  const m = (body || "").match(/Closes\s+(ENG-\d+)/i);
  return m ? m[1] : null;
};
const candidates = prs
  .map(p => ({ pr: p.number, linearId: extractLinearId(p.body) }))
  .filter(x => x.linearId);
candidates;
"}
